module top_module(clk, load, data, count);input clk, load;
input [7:0] data;
output reg [7:0] count;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
    if (load) begin
        count <= data;
    end else begin
        count <= count + 1;
    end
end

endmodule
